"""Zotero 联动工具模块"""
import os, re, json, time, shutil, sqlite3, logging, platform, pathlib
from typing import Optional, List

logger = logging.getLogger(__name__)

def detect_zotero_source(file_path: str) -> Optional[str]:
    m = re.search(r'[/\\][Zz]otero[/\\]storage[/\\][A-Za-z0-9]{8}[/\\]', file_path)
    return file_path[:m.end()] if m else None

def get_zotero_item_key(file_path: str) -> Optional[str]:
    m = re.search(r'[/\\][Zz]otero[/\\]storage[/\\]([A-Za-z0-9]{8})[/\\]', file_path)
    return m.group(1) if m else None

def _find_zotero_profile_dir_simple() -> Optional[str]:
    import glob
    appdata = os.environ.get("APPDATA", "")
    if appdata:
        for pd in [os.path.join(appdata, "Zotero", "Zotero", "Profiles"), os.path.join(appdata, "Zotero", "Profiles")]:
            profiles = glob.glob(os.path.join(pd, "*.default*"))
            if profiles: return profiles[0]
    return None

def _find_zotero_data_dir() -> Optional[str]:
    candidates = [os.path.expanduser("~/Zotero")]
    if platform.system() == "Windows":
        appdata = os.environ.get("APPDATA", "")
        if appdata: candidates.append(os.path.join(appdata, "Zotero", "Zotero"))
        candidates.append(os.path.expanduser("~\\Zotero"))
        profile = _find_zotero_profile_dir_simple()
        if profile:
            prefs_path = os.path.join(profile, "prefs.js")
            if os.path.exists(prefs_path):
                try:
                    with open(prefs_path, 'r', encoding='utf-8') as f:
                        for line in f:
                            if 'extensions.zotero.dataDir' in line and 'user_pref' in line:
                                m = re.search(r'"extensions\.zotero\.dataDir"\s*,\s*"([^"]+)"', line)
                                if m: candidates.insert(0, m.group(1).replace('\\\\', '\\'))
                except Exception: pass
        for drive in ['C','D','E','F']:
            candidates.append(f"{drive}:\\soft\\zotero")
            candidates.append(f"{drive}:\\Zotero")
    best, best_count = None, -1
    for d in candidates:
        db_path = os.path.join(d, "zotero.sqlite")
        if os.path.isfile(db_path):
            try:
                conn = sqlite3.connect(f"{pathlib.Path(db_path).as_uri()}?mode=ro&immutable=1", uri=True)
                count = conn.execute("SELECT COUNT(*) FROM items").fetchone()[0]
                conn.close()
                if count > best_count: best_count, best = count, d
            except Exception:
                if best is None: best = d
    return best

def _find_zotero_profile_dir() -> Optional[str]:
    import glob
    candidates = []
    appdata = os.environ.get("APPDATA", "")
    if appdata:
        candidates.append(os.path.join(appdata, "Zotero", "Zotero", "Profiles"))
        candidates.append(os.path.join(appdata, "Zotero", "Profiles"))
    candidates.append(os.path.expanduser("~\\Zotero\\Profiles"))
    for profiles_dir in candidates:
        if not os.path.isdir(profiles_dir): continue
        profiles = glob.glob(os.path.join(profiles_dir, "*.default*"))
        if profiles: return profiles[0]
    return None

def _open_zotero_db():
    data_dir = _find_zotero_data_dir()
    if not data_dir: return None
    db_path = os.path.join(data_dir, "zotero.sqlite")
    if not os.path.exists(db_path): return None
    return sqlite3.connect(f"{pathlib.Path(db_path).as_uri()}?mode=ro&immutable=1", uri=True)

def _get_base_attachment_path() -> Optional[str]:
    profile = _find_zotero_profile_dir_simple()
    if not profile: return None
    prefs = os.path.join(profile, "prefs.js")
    if not os.path.exists(prefs): return None
    try:
        with open(prefs, 'r', encoding='utf-8') as f:
            for line in f:
                if 'baseAttachmentPath' in line:
                    m = re.search(r'"extensions\.zotero\.baseAttachmentPath"\s*,\s*"([^"]+)"', line)
                    if m: return m.group(1).replace('\\\\', '\\')
    except Exception: pass
    return None

def zotero_writeback(file_path: str, output_files: dict, config: dict) -> List[str]:
    zotero_dir = detect_zotero_source(file_path)
    if not zotero_dir: return []
    modes = config.get("zotero_output_modes", ["side_by_side"])
    keep_copy = config.get("zotero_keep_copy", True)
    written = []
    for mode in modes:
        src = output_files.get(mode)
        if not src or not os.path.exists(src): continue
        dst = os.path.join(zotero_dir, os.path.basename(src))
        if os.path.abspath(src).lower() == os.path.abspath(dst).lower():
            written.append(dst); continue
        for attempt in range(3):
            try:
                shutil.copy2(src, dst); written.append(dst)
                if not keep_copy:
                    try: os.remove(src)
                    except OSError: pass
                break
            except PermissionError:
                if attempt < 2: time.sleep(0.5)
    item_key = get_zotero_item_key(file_path)
    if item_key and written:
        for dst_path in written:
            base_name = os.path.splitext(os.path.basename(dst_path))[0]
            for suffix in ["-side_by_side", "-dual", "-mono"]:
                if base_name.endswith(suffix): base_name = base_name[:-len(suffix)]; break
            mode_tag = ""
            for m, tag in [("side_by_side","side by side"),("dual","dual"),("mono","mono")]:
                if m in os.path.basename(dst_path): mode_tag = tag; break
            mode_label = f"{mode_tag} - {base_name}" if mode_tag else base_name
            try: zotero_auto_link(item_key, dst_path, mode_label)
            except Exception: pass
    return written

def zotero_auto_link(item_key: str, file_path: str, title: str) -> dict:
    import urllib.request
    payload = json.dumps({"itemKey": item_key, "filePath": os.path.abspath(file_path), "title": title}).encode("utf-8")
    req = urllib.request.Request("http://127.0.0.1:23119/pdf2zh/attach", data=payload, headers={"Content-Type": "application/json"}, method="POST")
    with urllib.request.urlopen(req, timeout=10) as resp:
        return json.loads(resp.read().decode())

def zotero_plugin_installed() -> bool:
    try:
        import urllib.request
        with urllib.request.urlopen(urllib.request.Request("http://127.0.0.1:23119/pdf2zh/ping", method="GET"), timeout=2) as resp:
            return json.loads(resp.read().decode()).get("status") == "ok"
    except Exception: return False

def resolve_zotero_items(item_ids: List[int]) -> List[str]:
    conn = _open_zotero_db()
    if not conn: return []
    data_dir = _find_zotero_data_dir()
    base_path = _get_base_attachment_path()
    results = []
    try:
        cursor = conn.cursor()
        for item_id in item_ids:
            cursor.execute("SELECT ia.path, i.key, ia.linkMode FROM itemAttachments ia JOIN items i ON i.itemID = ia.itemID WHERE ia.parentItemID = ? AND ia.contentType = 'application/pdf' ORDER BY ia.itemID ASC LIMIT 1", (item_id,))
            row = cursor.fetchone()
            if not row:
                cursor.execute("SELECT ia.path, i.key, ia.linkMode FROM itemAttachments ia JOIN items i ON i.itemID = ia.itemID WHERE ia.itemID = ? AND ia.contentType = 'application/pdf'", (item_id,))
                row = cursor.fetchone()
            if row:
                path_val, item_key, link_mode = row
                full_path = None
                if path_val:
                    if path_val.startswith("storage:"): full_path = os.path.join(data_dir, "storage", item_key, path_val[len("storage:"):])
                    elif path_val.startswith("attachments:") and base_path: full_path = os.path.join(base_path, path_val[len("attachments:"):])
                    elif os.path.isabs(path_val): full_path = path_val
                    else: full_path = os.path.join(data_dir, path_val)
                if full_path and os.path.exists(full_path): results.append(full_path)
    except Exception as e: logger.warning(f"Zotero SQLite query failed: {e}")
    finally: conn.close()
    return results

def resolve_zotero_collection(collection_id: int) -> List[str]:
    conn = _open_zotero_db()
    if not conn: return []
    try:
        cursor = conn.cursor()
        cursor.execute("SELECT itemID FROM collectionItems WHERE collectionID = ?", (collection_id,))
        item_ids = [row[0] for row in cursor.fetchall()]
        conn.close()
        return resolve_zotero_items(item_ids)
    except Exception: conn.close(); return []

def install_zotero_plugin() -> str:
    import subprocess
    base = os.path.dirname(os.path.abspath(__file__))
    xpi = None
    for c in [os.path.join(base,'..','..','..','assets','pdf2zh-connector.xpi'), os.path.join(base,'..','..','..','..','assets','pdf2zh-connector.xpi')]:
        if os.path.exists(c): xpi = os.path.abspath(c); break
    if not xpi: return "找不到插件文件"
    profile = _find_zotero_profile_dir()
    if not profile: return "找不到 Zotero 配置目录"
    try:
        plugin_id = "pdf2zh-connector@aarongig.com"
        ext_dir = os.path.join(profile, "extensions"); os.makedirs(ext_dir, exist_ok=True)
        # 清理旧的解压目录（如有）
        plugin_dir = os.path.join(ext_dir, plugin_id)
        if os.path.isdir(plugin_dir): shutil.rmtree(plugin_dir)
        # 复制 XPI 到 extensions 目录
        dst = os.path.join(ext_dir, f"{plugin_id}.xpi"); shutil.copy2(xpi, dst)
        # 在 extensions.json 中注册我们的插件（只增不删，保留其他插件）
        ext_json_path = os.path.join(profile, "extensions.json")
        try:
            if os.path.exists(ext_json_path):
                ext_data = json.load(open(ext_json_path, 'r', encoding='utf-8', errors='replace'))
            else:
                ext_data = {"addons": []}
            # 移除旧的同 ID 条目，再添加新条目
            addons = ext_data.get("addons", [])
            addons = [a for a in addons if a.get("id") != plugin_id]
            addons.append({
                "id": plugin_id, "type": "extension", "version": "1.0.5",
                "active": True, "visible": True, "userDisabled": False,
                "appDisabled": False, "path": dst,
                "rootURI": f"jar:file:///{dst.replace(chr(92), '/')}!/",
                "location": "app-profile",
            })
            ext_data["addons"] = addons
            json.dump(ext_data, open(ext_json_path, 'w', encoding='utf-8'), ensure_ascii=False, indent=2)
        except Exception as e:
            logger.warning(f"Failed to update extensions.json: {e}")
        # 确保 prefs.js 允许非商店插件（读取时容错编码）
        prefs_path = os.path.join(profile, "prefs.js")
        try:
            content = open(prefs_path, 'r', encoding='utf-8', errors='replace').read()
            if 'autoDisableScopes' not in content:
                open(prefs_path, 'a', encoding='utf-8').write('user_pref("extensions.autoDisableScopes", 0);\n')
        except FileNotFoundError:
            open(prefs_path, 'w', encoding='utf-8').write('user_pref("extensions.autoDisableScopes", 0);\n')
        # 删除启动缓存，让 Zotero 重启时重新加载插件注册
        for cn in ["addonStartup.json.lz4"]:
            cp = os.path.join(profile, cn)
            if os.path.exists(cp):
                try: os.remove(cp)
                except OSError: pass
        # 重启 Zotero
        subprocess.run(["taskkill", "/f", "/im", "zotero.exe"], capture_output=True); time.sleep(2)
        zotero_exe = None
        try:
            import winreg
            key = winreg.OpenKey(winreg.HKEY_LOCAL_MACHINE, r"SOFTWARE\Microsoft\Windows\CurrentVersion\App Paths\zotero.exe")
            zotero_exe = winreg.QueryValue(key, None); winreg.CloseKey(key)
        except Exception: pass
        if not zotero_exe or not os.path.exists(zotero_exe):
            for zp in [r"C:\Program Files\Zotero\zotero.exe", r"D:\Program Files\Zotero\zotero.exe",
                       r"C:\Program Files (x86)\Zotero\zotero.exe", r"E:\Program Files\Zotero\zotero.exe"]:
                if os.path.exists(zp): zotero_exe = zp; break
        if zotero_exe and os.path.exists(zotero_exe): subprocess.Popen([zotero_exe])
        return "ok"
    except Exception as e: return f"安装失败: {e}"
